// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle
#:property PublishAot=false

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (proleptic Gregorian)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: distribution by month
var byMonth = Enumerable.Range(1, 12)
    .Select(m => new {
        Month = new DateTime(2000, m, 1).ToString("MMMM"),
        Count = Enumerable.Range(1, 400).Count(y => new DateTime(y, m, 13).DayOfWeek == DayOfWeek.Friday)
    });

Console.WriteLine("\nDistribution by month (400-year cycle):");
foreach (var entry in byMonth)
    Console.WriteLine($"  {entry.Month,-12} {entry.Count}");

